#!/bin/bash
set -euo pipefail
NAME=${1:?Usage: run-job.sh <name> <image> <command...>}
IMAGE=${2:?Usage: run-job.sh <name> <image> <command...>}
shift 2
NS=${KUBE_NAMESPACE:-default}

echo "Creating Job $NAME with image $IMAGE in namespace $NS"
kubectl create job "$NAME" --image="$IMAGE" -n "$NS" -- "$@"

echo "Waiting for Job to complete..."
kubectl wait --for=condition=complete job/"$NAME" -n "$NS" --timeout=300s 2>/dev/null || {
  echo "Job did not complete successfully. Checking status..."
  kubectl describe job "$NAME" -n "$NS" | tail -20
}

echo ""
echo "=== Job Logs ==="
kubectl logs job/"$NAME" -n "$NS"
